import { useState } from 'react';
import {
    Box,
    Paper,
    IconButton,
    Typography,
} from '@mui/material';
import {
    AddPhotoAlternate as AddPhotoIcon,
    Delete as DeleteIcon,
    Edit as EditIcon
} from '@mui/icons-material';
import { motion } from 'framer-motion';
import ImageEditor from './ImageEditor';

const MotionPaper = motion(Paper);

const PhotoBookPage = ({ format, photos, onPhotoAdd, onPhotoRemove, onPhotoEdit, pageNumber }) => {
    const [isEditorOpen, setIsEditorOpen] = useState(false);
    const [selectedPhoto, setSelectedPhoto] = useState(null);

    // Вычисляем размеры страницы на основе формата
    const getPageDimensions = () => {
        const baseWidth = 600; // Базовая ширина для отображения
        const [width, height] = format.size.split('×').map(dim => parseInt(dim));
        const ratio = height / width;
        return {
            width: baseWidth,
            height: baseWidth * ratio
        };
    };

    const handleDragOver = (e) => {
        e.preventDefault();
        e.currentTarget.style.backgroundColor = 'rgba(0, 0, 0, 0.04)';
    };

    const handleDragLeave = (e) => {
        e.preventDefault();
        e.currentTarget.style.backgroundColor = '';
    };

    const handleDrop = (e, position) => {
        e.preventDefault();
        try {
            const photoData = JSON.parse(e.dataTransfer.getData('photo'));
            onPhotoAdd(pageNumber, position, photoData);
        } catch (error) {
            console.error('Error adding photo:', error);
        }
    };

    const handleEdit = (photo) => {
        setSelectedPhoto(photo);
        setIsEditorOpen(true);
    };

    const handleEditorClose = () => {
        setIsEditorOpen(false);
        setSelectedPhoto(null);
    };

    const handlePhotoSave = (editedBlob) => {
        if (selectedPhoto) {
            onPhotoEdit(pageNumber, selectedPhoto.position, editedBlob);
        }
        handleEditorClose();
    };

    const { width, height } = getPageDimensions();

    // Создаем сетку 2x2 для размещения фотографий
    const grid = Array(4).fill(null).map((_, index) => {
        const photo = photos.find(p => p.position === index);

        return (
            <Box
                key={index}
                sx={{
                    position: 'relative',
                    width: '100%',
                    height: '100%',
                    border: '2px dashed',
                    borderColor: photo ? 'transparent' : 'grey.300',
                    borderRadius: 1,
                    overflow: 'hidden',
                    transition: 'all 0.2s ease-in-out',
                    '&:hover': {
                        borderColor: photo ? 'transparent' : 'primary.main',
                        backgroundColor: photo ? 'transparent' : 'action.hover',
                    },
                }}
                onDrop={(e) => handleDrop(e, index)}
                onDragOver={handleDragOver}
                onDragLeave={handleDragLeave}
            >
                {photo ? (
                    <Box sx={{ position: 'relative', width: '100%', height: '100%' }}>
                        <img
                            src={photo.preview}
                            alt={`Photo ${index + 1}`}
                            style={{
                                width: '100%',
                                height: '100%',
                                objectFit: 'cover'
                            }}
                        />
                        <Box
                            sx={{
                                position: 'absolute',
                                top: 0,
                                right: 0,
                                display: 'flex',
                                gap: 1,
                                padding: 1
                            }}
                        >
                            <IconButton
                                size="small"
                                onClick={() => handleEdit(photo)}
                                sx={{ bgcolor: 'white' }}
                            >
                                <EditIcon fontSize="small" />
                            </IconButton>
                            <IconButton
                                size="small"
                                onClick={() => onPhotoRemove(pageNumber, index)}
                                sx={{ bgcolor: 'white' }}
                            >
                                <DeleteIcon fontSize="small" />
                            </IconButton>
                        </Box>
                    </Box>
                ) : (
                    <Box
                        sx={{
                            width: '100%',
                            height: '100%',
                            display: 'flex',
                            alignItems: 'center',
                            justifyContent: 'center',
                            color: 'grey.500',
                        }}
                    >
                        <AddPhotoIcon sx={{ fontSize: 40 }} />
                    </Box>
                )}
            </Box>
        );
    });

    return (
        <Box sx={{ mb: 4 }}>
            <Typography variant="h6" gutterBottom align="center">
                Страница {pageNumber + 1}
            </Typography>
            <MotionPaper
                elevation={3}
                sx={{
                    width,
                    height,
                    margin: '0 auto',
                    position: 'relative',
                    backgroundColor: '#fff',
                    display: 'grid',
                    gridTemplateColumns: 'repeat(2, 1fr)',
                    gridTemplateRows: 'repeat(2, 1fr)',
                    gap: 2,
                    p: 2,
                    boxSizing: 'border-box',
                }}
            >
                {grid}
            </MotionPaper>

            {selectedPhoto && (
                <ImageEditor
                    open={isEditorOpen}
                    onClose={handleEditorClose}
                    image={selectedPhoto.file}
                    onSave={handlePhotoSave}
                />
            )}
        </Box>
    );
};

export default PhotoBookPage;
